/**
 * @fileoverview DataTable barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/DataTable
 */
import { default as razyui } from '../index.js';
import { DataTableDef as DEF } from './DataTable.def.js';
import DataTable from './DataTable/index.js';

// ── Module registration ──
razyui.DataTable = DataTable;

// Ensure shared keyframes are available for styles-block animations
razyui.motion.use('spin');

// ── JIT Component Definition registration ──
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

// ── Custom Element registration ──
export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, DataTable);
}

export default DataTable;
export const stylesheet = null;
