/**
 * @fileoverview DataTable — Simple semantic `<table>` component with AJAX fetch
 * and infinite-scroll lazy loading.
 *
 * A lighter alternative to GridTable that uses real `<table>`, `<thead>`,
 * `<tbody>`, `<tr>`, `<th>`, `<td>` elements. Perfect for SEO-friendly,
 * accessible data tables that don't need full virtualisation.
 *
 * Features:
 *   - Semantic HTML `<table>` structure
 *   - Column sorting (click header)
 *   - Column filters (keyword text input or Combobox dropdown)
 *   - AJAX fetch with pagination footer
 *   - Infinite-scroll lazy loading (append rows on scroll)
 *   - Loading / empty / error states
 *   - Stripe, hover, bordered, compact variants
 *   - getControl() public API
 *
 * @module module/DataTable
 */

import { default as razyui } from '../../index.js';
import Icons from '../Icons.js';
import { setContent } from '../shared/setContent.js';
import { PART } from './constants.js';

const { getNestedValue } = razyui;

// ── Defaults ─────────────────────────────────────────────────────────

const DEFAULTS = {
    pageSize:      20,
    threshold:     200,      // px from bottom to trigger next fetch
    method:        'GET',
    dataKey:       'data',
    totalKey:      'total',
    emptyMessage:  'No data available',
    errorMessage:  'Failed to load data',
    loadingText:   'Loading…',
    endMessage:    'All data loaded',
    debounce:      150,
};

// ── DataTable class ──────────────────────────────────────────────────

const DataTable = class {

    // ── private fields ──────────────────────────

    #el            = null;   // target wrapper element
    #config        = {};
    #columns       = [];     // [{key, label, sortable, width, align, onPrint, printHTML}]
    #headerRows    = [];     // [{ cells: [{ text|content, colspan?, rowspan?, align?, className? }], className? }]
    #data          = [];
    #displayData   = [];     // after sort

    // DOM references (Elements collections)
    #container     = null;   // .data-table-container
    #table         = null;   // <table>
    #thead         = null;   // <thead>
    #tbody         = null;   // <tbody>
    #footer        = null;   // pagination footer
    #emptyRow      = null;
    #loadingRow    = null;
    #sentinel      = null;   // infinite scroll sentinel

    // Sort state
    #sortCol       = null;
    #sortDir       = null;   // 'asc' | 'desc'

    // Filter state
    #filterValues  = {};     // { colKey: currentValue }
    #filterTimer   = 0;      // debounce timer for keyword filters
    #filterRow     = null;   // <tr> filter row in thead
    #filterInputs  = {};     // { colKey: inputEl | comboboxInstance }
    #hasFilters    = false;  // true if any column defines a filter

    // AJAX state
    #ajax          = null;   // config object when using ajax mode
    #ajaxPage      = 1;
    #ajaxTotal     = 0;
    #ajaxLoading   = false;

    // Infinite-scroll state
    #infinite      = null;   // config object when using infinite mode
    #infPage       = 0;
    #infHasMore    = true;
    #infLoading    = false;
    #infObserver   = null;
    #infScrollCleanup = null;

    #destroyed     = false;
    #eventAC     = new AbortController();

    // ────────────────────────────────────────────
    // Constructor
    // ────────────────────────────────────────────

    constructor(selector, config = {}) {
        const el = razyui.isStr(selector) ? razyui(selector)[0] : selector;
        if (!el) { console.warn('DataTable: element not found \u2192', selector); return; }

        this.#el = el;
        this.#config = { ...DEFAULTS, ...config };
        this.#columns = this.#normaliseColumns(config.columns || {});
        this.#headerRows = this.#normaliseHeaderRows(config.headerRows || []);

        // ── Build DOM ──
        this.#buildDOM();

        // ── AJAX mode ──
        if (config.ajax) {
            this.#ajax = { ...DEFAULTS, ...config.ajax };
            this.#buildFooter();
            this.#ajaxFetch();
        }
        // ── Infinite scroll mode ──
        else if (config.infinite) {
            this.#infinite = { ...DEFAULTS, ...config.infinite };
            if (typeof this.#infinite.fetch !== 'function') {
                console.warn('DataTable: infinite.fetch callback is required');
                this.#infinite = null;
            } else {
                this.#buildSentinel();
                this.#bindInfiniteScroll();
                this.#infFetchNext();
            }
        }
        // ── Static data mode ──
        else if (config.data) {
            this.setData(config.data);
        }
    }

    #normaliseHeaderRows(rows) {
        if (!Array.isArray(rows)) return [];
        return rows
            .map((row) => {
                const cells = Array.isArray(row)
                    ? row
                    : (Array.isArray(row?.cells) ? row.cells : []);
                if (cells.length === 0) return null;
                return {
                    className: (!Array.isArray(row) && row?.className) ? String(row.className) : '',
                    cells: cells.map((cell) => {
                        if (razyui.isPO(cell)) return { ...cell };
                        return { text: cell };
                    }),
                };
            })
            .filter(Boolean);
    }

    #renderHeader() {
        const $ = razyui;
        this.#thead.html('');

        // Optional grouped header rows
        for (const rowDef of this.#headerRows) {
            const tr = $.spell('tr.data-table-header-group', true);
            if (rowDef.className) tr.addClass(...rowDef.className.split(' '));

            for (const cellDef of rowDef.cells) {
                const th = $.spell('th', true);
                const colspan = Number(cellDef.colspan || 1);
                const rowspan = Number(cellDef.rowspan || 1);

                if (cellDef.className) th.addClass(...String(cellDef.className).split(' '));
                if (cellDef.align) th.css('text-align', cellDef.align);
                if (colspan > 1) th.attr('colspan', colspan);
                if (rowspan > 1) th.attr('rowspan', rowspan);

                if (cellDef.content != null) {
                    setContent(th, cellDef.content);
                } else if (cellDef.html != null) {
                    setContent(th, cellDef.html);
                } else {
                    th.text(cellDef.text ?? cellDef.label ?? cellDef.value ?? '');
                }

                tr.append(th);
            }

            this.#thead.append(tr);
        }

        // Main data header row
        const headerRow = $.spell('tr', true);

        for (const col of this.#columns) {
            const th = $.spell('th', true);
            PART.THEAD_TH.apply(th);
            th.text(col.label).attr('data-key', col.key);
            if (col.width)    th.css('width', typeof col.width === 'number' ? col.width + 'px' : col.width);
            if (col.minWidth) th.css('min-width', typeof col.minWidth === 'number' ? col.minWidth + 'px' : col.minWidth);
            if (col.align)    th.css('text-align', col.align);
            if (col.nowrap)   th.addClass('is-nowrap');
            if (col.ellipsis) th.addClass('is-ellipsis');
            if (col.sortable) {
                th.addClass('is-sortable');
                if (col.align === 'right') th.addClass('is-align-right');
                const sortIcon = $.spell('span.data-table-sort-icon', true);
                PART.SORT_ICON.apply(sortIcon);
                sortIcon.html(Icons.svg('arrow-up-down', { size: 12, strokeWidth: 2 }));
                th.append(sortIcon);
            }
            headerRow.append(th);
        }

        this.#thead.append(headerRow);

        // Filter row — built lazily via enableFilters()
    }

    // ────────────────────────────────────────────
    // Column normalisation
    // ────────────────────────────────────────────

    /**
     * Accepts columns as object or array and normalises to internal format.
     * @param {Object|Array} raw
     * @returns {Array<{key, label, sortable, width, align, onPrint, printHTML}>}
     */
    #normaliseColumns(raw) {
        const normalise = (c, key) => {
            if (typeof c === 'string') return { key: c, label: c, sortable: true, filter: null };
            const obj = {
                key:       key || c.key || c.name || c.field,
                label:     c.label || c.header || c.key || key || '',
                sortable:  c.sortable !== false,
                width:     c.width || null,
                minWidth:  c.minWidth || c.min_width || null,
                align:     c.align || null,
                nowrap:    !!c.nowrap,
                ellipsis:  !!c.ellipsis,
                onPrint:   c.onPrint || null,
                printHTML: !!c.printHTML,
                filter:    null,
            };
            return obj;
        };

        if (Array.isArray(raw)) {
            return raw.map(c => normalise(c));
        }
        // Object map: { key: { label, ... } }
        return Object.entries(raw).map(([key, def]) => {
            if (typeof def === 'string') return { key, label: def, sortable: true, filter: null  };
            return normalise(def, key);
        });
    }

    // ────────────────────────────────────────────
    // Filter row  (lazy — built by enableFilters())
    // ────────────────────────────────────────────

    /**
     * Enable column filters.
     * Call via `getControl().enableFilters(filterMap)` where filterMap is:
     *   { colKey: 'keyword' | 'select' | 'date' | { type, options?, placeholder?, filterKey? }, ... }
     *
     * `filterKey` optionally maps the display column to a different server/DB
     * column name (e.g. column `status_text` → filterKey `status`).
     *
     * @param {Object} filterMap — keyed by column key
     */
    enableFilters(filterMap) {
        if (!filterMap || !razyui.isPO(filterMap)) return;
        if (this.#hasFilters) return;   // already enabled

        // Apply filter defs onto the matching columns
        for (const col of this.#columns) {
            const def = filterMap[col.key];
            if (!def) continue;
            if (typeof def === 'string') {
                col.filter = { type: def };
            } else if (razyui.isPO(def)) {
                col.filter = { ...def };
            }
        }

        this.#hasFilters = this.#columns.some(c => c.filter);
        if (this.#hasFilters) {
            this.#buildFilterRow();
        }
    }

    /**
     * Build the filter `<tr>` and append to `<thead>`.
     * Three types:
     *   - `keyword`  → debounced text `<input>`
     *   - `select`   → `<select>` → lazy-load Combobox with provided options
     *   - `date`     → read-only `<input>` → lazy-load DatePicker (range mode)
     */
    #buildFilterRow() {
        const $ = razyui;
        const tr = $.spell('tr.data-table-filter-row', true);
        PART.FILTER_ROW.apply(tr);

        for (const col of this.#columns) {
            const td = $.spell('td.data-table-filter-cell', true);
            PART.FILTER_CELL.apply(td);
            if (col.width)    td.css('width', typeof col.width === 'number' ? col.width + 'px' : col.width);
            if (col.minWidth) td.css('min-width', typeof col.minWidth === 'number' ? col.minWidth + 'px' : col.minWidth);

            if (!col.filter) {
                // Empty cell — no filter for this column
                tr.append(td);
                continue;
            }

            const filterDef = col.filter;
            this.#filterValues[col.key] = '';

            if (filterDef.type === 'select') {
                // ── Combobox filter ──
                const selectEl = $.el('select', { multiple: true });
                td.append(selectEl);

                razyui.load('Combobox').then((Combobox) => {
                    const options = Array.isArray(filterDef.options) ? filterDef.options : [];
                    const sb = new Combobox(selectEl[0], {
                        placeholder: filterDef.placeholder || '\u25BE Filter',
                        renderContext: 'grid-filter',
                        onSelect: (selected) => {
                            const val = (selected == null || (Array.isArray(selected) && selected.length === 0))
                                ? ''
                                : (Array.isArray(selected) ? selected.join(',') : String(selected));
                            this.#filterValues[col.key] = val;
                            this.#onFilterChange();
                        },
                    });
                    sb.setOptions(options);
                    this.#filterInputs[col.key] = sb;
                });
            } else if (filterDef.type === 'date') {
                // ── DatePicker range filter ──
                const inp = $.el('input', {
                    type: 'text',
                    readOnly: true,
                    placeholder: filterDef.placeholder || 'Date range…',
                    className: 'data-table-filter-input',
                });
                PART.FILTER_INPUT.apply(inp);
                td.append(inp);

                const resetBtn = $.el('span', {
                    className: 'data-table-filter-reset',
                    innerHTML: Icons.svg('x', { size: 12, strokeWidth: 2 }),
                    title: 'Clear date filter',
                });
                PART.FILTER_RESET.apply(resetBtn);
                td.append(resetBtn);
                td.css('position', 'relative');

                resetBtn.on('click', () => {
                    const dpRef = this.#filterInputs[col.key];
                    if (dpRef && typeof dpRef.clear === 'function') dpRef.clear();
                    this.#filterValues[col.key] = '';
                    this.#onFilterChange();
                }, { signal: this.#eventAC.signal });

                razyui.load('DatePicker').then((DatePicker) => {
                    const dp = new DatePicker(inp[0], {
                        type: 'date',
                        mode: 'range',
                        placeholder: filterDef.placeholder || 'Date range…',
                        renderContext: 'grid-filter',
                        onChange: (value) => {
                            if (!value) {
                                this.#filterValues[col.key] = '';
                            } else {
                                const parts = String(value).split('~').map(s => s.trim());
                                this.#filterValues[col.key] = {
                                    from: parts[0] || null,
                                    to:   parts[1] || parts[0] || null,
                                };
                            }
                            this.#onFilterChange();
                        },
                    });
                    this.#filterInputs[col.key] = dp;
                });
            } else {
                // ── Keyword text filter (default) ──
                const input = $.el('input', {
                    type: 'text',
                    placeholder: filterDef.placeholder || '',
                    className: 'data-table-filter-input',
                });
                PART.FILTER_INPUT.apply(input);
                td.append(input);

                input.on('input', () => {
                    clearTimeout(this.#filterTimer);
                    this.#filterTimer = setTimeout(() => {
                        this.#filterValues[col.key] = input[0].value;
                        this.#onFilterChange();
                    }, this.#config.debounce);
                }, { signal: this.#eventAC.signal });

                this.#filterInputs[col.key] = input[0];
            }

            tr.append(td);
        }

        this.#filterRow = tr;
        this.#thead.append(tr);
    }

    /**
     * Called whenever a filter value changes.
     * AJAX/infinite → re-fetch from page 1 with filter params.
     * Static → apply client-side filter + sort.
     */
    #onFilterChange() {
        if (this.#ajax) {
            this.#ajaxPage = 1;
            this.#ajaxFetch();
        } else if (this.#infinite) {
            this.infiniteReset();
        } else {
            this.#applySortAndRender();
        }
    }

    /**
     * Get the current filter values as a plain object (keys with empty values omitted).
     * @returns {Object<string, string>}
     */
    #getActiveFilters() {
        const result = {};
        for (const [k, v] of Object.entries(this.#filterValues)) {
            const col = this.#columns.find(c => c.key === k);
            const outKey = col?.filter?.filterKey || k;
            if (razyui.isPO(v) && (v.from || v.to)) { result[outKey] = v; continue; }
            if (v !== '' && v != null) result[outKey] = v;
        }
        return result;
    }

    // ────────────────────────────────────────────
    // DOM construction
    // ────────────────────────────────────────────

    #buildDOM() {
        const $ = razyui;

        // Container
        this.#container = $.spell('div.data-table-container', true);
        PART.CONTAINER.apply(this.#container);

        // Variant classes
        if (this.#config.striped)   this.#container.addClass('is-striped');
        if (this.#config.bordered)  this.#container.addClass('is-bordered');
        if (this.#config.compact)   this.#container.addClass('is-compact');
        if (this.#config.hover !== false) this.#container.addClass('is-hoverable');

        // Scroll wrapper
        const wrapper = $.spell('div.data-table-wrapper', true);
        PART.WRAPPER.apply(wrapper);

        // Table
        this.#table = $.spell('table.data-table', true);
        PART.TABLE.apply(this.#table);

        // Thead
        this.#thead = $.spell('thead', true);
        PART.THEAD.apply(this.#thead);
        this.#renderHeader();

        // Tbody
        this.#tbody = $.spell('tbody', true);

        this.#table.append(this.#thead, this.#tbody);
        wrapper.append(this.#table);
        this.#container.append(wrapper);

        // Mount
        $(this.#el).html('').append(this.#container);

        // ── Header click → sort ──
        this.#thead.on('click', (e) => {
            const th = e.target.closest('th[data-key]');
            if (!th || !razyui(th).hasClass('is-sortable')) return;
            this.#toggleSort(th.dataset.key);
        }, { signal: this.#eventAC.signal });
    }

    // ────────────────────────────────────────────
    // Row rendering
    // ────────────────────────────────────────────

    /**
     * Render the full tbody from #displayData.
     */
    #renderRows() {
        this.#tbody.html('');   // fast clear

        if (this.#displayData.length === 0) {
            this.#showEmpty();
            return;
        }
        this.#hideEmpty();

        const frag = document.createDocumentFragment();
        for (let i = 0; i < this.#displayData.length; i++) {
            frag.appendChild(this.#createRow(this.#displayData[i], i));
        }
        this.#tbody.append(frag);
    }

    /**
     * Append rows (for infinite scroll).
     * @param {Array} rows
     */
    #appendRows(rows) {
        this.#hideEmpty();
        const frag = document.createDocumentFragment();
        const startIndex = this.#displayData.length - rows.length;
        for (let i = 0; i < rows.length; i++) {
            frag.appendChild(this.#createRow(rows[i], startIndex + i));
        }
        this.#tbody.append(frag);
    }

    /**
     * Create a single `<tr>` for a data row.
     */
    #createRow(rowData, index) {
        const $ = razyui;
        const tr = $.spell('tr', true).attr('data-index', index);

        const customCells = rowData?.__cells || rowData?.$cells || rowData?.cells;
        if (Array.isArray(customCells)) {
            if (rowData?.className) tr.addClass(...String(rowData.className).split(' '));

            for (const cellDefRaw of customCells) {
                const cellDef = razyui.isPO(cellDefRaw) ? cellDefRaw : { text: cellDefRaw };
                const td = $.spell('td', true);

                const colspan = Number(cellDef.colspan || 1);
                const rowspan = Number(cellDef.rowspan || 1);
                if (colspan > 1) td.attr('colspan', colspan);
                if (rowspan > 1) td.attr('rowspan', rowspan);
                if (cellDef.className) td.addClass(...String(cellDef.className).split(' '));
                if (cellDef.align) td.css('text-align', cellDef.align);

                if (cellDef.content != null) {
                    setContent(td, cellDef.content);
                } else if (cellDef.html != null || cellDef.printHTML) {
                    setContent(td, cellDef.html ?? cellDef.value ?? '');
                } else {
                    td.text(cellDef.text ?? cellDef.value ?? '');
                }

                tr.append(td);
            }

            return tr[0];
        }

        for (const col of this.#columns) {
            const td = $.spell('td', true);
            PART.TBODY_TD.apply(td);
            if (col.align)    td.css('text-align', col.align);
            if (col.nowrap)   td.addClass('is-nowrap');
            if (col.ellipsis) td.addClass('is-ellipsis');

            const raw = getNestedValue(rowData, col.key) ?? '';
            if (col.onPrint) {
                const val = col.onPrint(raw, rowData, index);
                if (col.printHTML) {
                    setContent(td, val);
                } else {
                    td.text(val);
                }
            } else if (razyui.isPO(raw)) {
                td.text(raw.label ?? raw.value ?? raw.text ?? String(raw));
            } else {
                td.text(raw);
            }

            tr.append(td);
        }
        return tr[0];
    }

    // ────────────────────────────────────────────
    // Empty / loading states
    // ────────────────────────────────────────────

    #showEmpty(msg) {
        if (this.#emptyRow) razyui(this.#emptyRow).detach();
        const $ = razyui;
        const tr = $.spell('tr.data-table-empty-row', true);
        PART.EMPTY_ROW.apply(tr);
        const td = $.spell('td', true).attr('colspan', this.#columns.length).text(msg || this.#config.emptyMessage);
        tr.append(td);
        this.#tbody.append(tr);
        this.#emptyRow = tr[0];
    }

    #hideEmpty() {
        if (this.#emptyRow) {
            razyui(this.#emptyRow).detach();
            this.#emptyRow = null;
        }
    }

    #showLoading() {
        this.#container.addClass('is-loading');
    }

    #hideLoading() {
        this.#container.removeClass('is-loading');
    }

    #showError(msg) {
        this.#tbody.html('');
        this.#showEmpty(msg || this.#config.errorMessage);
        if (this.#emptyRow) razyui(this.#emptyRow).addClass('is-error');
    }

    // ────────────────────────────────────────────
    // Sorting
    // ────────────────────────────────────────────

    #toggleSort(key) {
        if (this.#sortCol === key) {
            this.#sortDir = this.#sortDir === 'asc' ? 'desc' : null;
            if (!this.#sortDir) { this.#sortCol = null; }
        } else {
            this.#sortCol = key;
            this.#sortDir = 'asc';
        }

        this.#updateSortIndicators();

        // AJAX mode → server-side sort
        if (this.#ajax) {
            this.#ajaxPage = 1;
            this.#ajaxFetch();
            return;
        }

        this.#applySortAndRender();
    }

    #applySortAndRender() {
        let working = [...this.#data];

        // ── Client-side filtering (static data mode) ──
        if (!this.#ajax && !this.#infinite) {
            const filters = this.#getActiveFilters();
            if (Object.keys(filters).length > 0) {
                working = working.filter(row => {
                    for (const [colKey, filterVal] of Object.entries(filters)) {
                        const col = this.#columns.find(c => c.key === colKey);
                        if (!col) continue;
                        const raw = getNestedValue(row, colKey) ?? '';
                        const cellText = (razyui.isPO(raw) ? (raw.label ?? raw.value ?? '') : String(raw));

                        if (col.filter?.type === 'date' && razyui.isPO(filterVal)) {
                            // Date range filter { from, to }
                            if (filterVal.from && cellText < filterVal.from) return false;
                            if (filterVal.to && cellText > filterVal.to + '\uffff') return false;
                        } else if (col.filter?.type === 'select') {
                            // Exact match (comma-separated for multi)
                            const selected = filterVal.split(',');
                            if (!selected.some(v => cellText.toLowerCase() === v.toLowerCase())) return false;
                        } else {
                            // Keyword substring
                            if (!cellText.toLowerCase().includes(filterVal.toLowerCase())) return false;
                        }
                    }
                    return true;
                });
            }
        }

        // ── Sorting ──
        if (this.#sortCol) {
            const key = this.#sortCol;
            const dir = this.#sortDir;
            working.sort((a, b) => {
                let va = getNestedValue(a, key) ?? '';
                let vb = getNestedValue(b, key) ?? '';
                if (razyui.isPO(va)) va = va.value ?? va.label ?? '';
                if (razyui.isPO(vb)) vb = vb.value ?? vb.label ?? '';
                if (typeof va === 'number' && typeof vb === 'number') {
                    return dir === 'asc' ? va - vb : vb - va;
                }
                va = String(va).toLowerCase();
                vb = String(vb).toLowerCase();
                if (va < vb) return dir === 'asc' ? -1 : 1;
                if (va > vb) return dir === 'asc' ? 1 : -1;
                return 0;
            });
        }

        this.#displayData = working;
        this.#renderRows();
    }

    #updateSortIndicators() {
        this.#thead.find('th[data-key]').each((th) => {
            const $th = razyui(th);
            $th.removeClass('is-sort-asc is-sort-desc');
            const iconEl = $th.find('.data-table-sort-icon');
            if (th.dataset.key === this.#sortCol && this.#sortDir) {
                $th.addClass('is-sort-' + this.#sortDir);
                iconEl.html(Icons.svg(this.#sortDir === 'asc' ? 'sort-asc' : 'sort-desc', { size: 12, strokeWidth: 2 }));
            } else {
                iconEl.html(Icons.svg('arrow-up-down', { size: 12, strokeWidth: 2 }));
            }
        });
    }

    // ────────────────────────────────────────────
    // AJAX pagination
    // ────────────────────────────────────────────

    #ajaxFetch() {
        if (!this.#ajax || this.#ajaxLoading) return;
        this.#ajaxLoading = true;
        this.#showLoading();

        const cfg = this.#ajax;
        const url = new URL(cfg.url, location.href);
        url.searchParams.set('page',     this.#ajaxPage);
        url.searchParams.set('pageSize', cfg.pageSize);
        if (this.#sortCol) {
            url.searchParams.set('sortColumn',    this.#sortCol);
            url.searchParams.set('sortDirection',  this.#sortDir);
        }

        // Append active filter values as query params: filter[colKey]=value
        // Date range → filter[colKey.from] & filter[colKey.to]
        const filters = this.#getActiveFilters();
        for (const [k, v] of Object.entries(filters)) {
            if (razyui.isPO(v) && ('from' in v || 'to' in v)) {
                if (v.from) url.searchParams.set('filter[' + k + '.from]', v.from);
                if (v.to)   url.searchParams.set('filter[' + k + '.to]', v.to);
            } else {
                url.searchParams.set('filter[' + k + ']', v);
            }
        }

        // Custom params
        if (razyui.isFn(cfg.onBeforeRequest)) {
            const extra = cfg.onBeforeRequest({
                page: this.#ajaxPage, pageSize: cfg.pageSize,
                sort: this.#sortCol ? { column: this.#sortCol, direction: this.#sortDir } : null,
                filters,
            });
            if (extra) {
                for (const [k, v] of Object.entries(extra)) {
                    url.searchParams.set(k, v);
                }
            }
        }

        fetch(url.toString(), { method: cfg.method, signal: this.#eventAC.signal })
            .then(r => r.json())
            .then(result => {
                this.#ajaxLoading = false;
                this.#hideLoading();

                let data, total;
                if (razyui.isFn(cfg.onResponse)) {
                    const parsed = cfg.onResponse(result);
                    data = parsed.data;
                    total = parsed.total;
                } else {
                    data  = cfg.dataKey  ? result[cfg.dataKey]  : result;
                    total = cfg.totalKey ? result[cfg.totalKey] : (Array.isArray(data) ? data.length : 0);
                }

                this.#ajaxTotal = total;
                this.#data = Array.isArray(data) ? data : [];
                this.#displayData = [...this.#data];
                this.#renderRows();
                this.#renderPagination();
            })
            .catch(err => {
                if (err.name === 'AbortError') return;
                this.#ajaxLoading = false;
                this.#hideLoading();
                this.#showError(err?.message);
                if (razyui.isFn(this.#ajax.onError)) this.#ajax.onError(err);
            });
    }

    // ────────────────────────────────────────────
    // Pagination footer
    // ────────────────────────────────────────────

    #buildFooter() {
        this.#footer = razyui.spell('div.data-table-footer', true);
        PART.FOOTER.apply(this.#footer);
        this.#container.append(this.#footer);
    }

    #renderPagination() {
        if (!this.#footer || !this.#ajax) return;
        this.#footer.html('');

        const $ = razyui;
        const total     = this.#ajaxTotal;
        const pageSize  = this.#ajax.pageSize;
        const totalPages = Math.max(1, Math.ceil(total / pageSize));
        const page      = this.#ajaxPage;
        const from      = Math.min((page - 1) * pageSize + 1, total);
        const to        = Math.min(page * pageSize, total);

        // Info
        const info = $.spell('span.data-table-footer-info', true)
            .text(total > 0 ? `${from}\u2013${to} of ${total}` : 'No records');
        PART.FOOTER_INFO.apply(info);
        this.#footer.append(info);

        // Nav
        const nav = $.spell('div.data-table-footer-nav', true);
        PART.FOOTER_NAV.apply(nav);

        const btn = (label, pg, disabled) => {
            const b = $.spell('button', true)
                .attr({ type: 'button', 'data-page': pg })
                .html(label)
                .prop('disabled', disabled);
            PART.NAV_BUTTON.apply(b);
            return b;
        };

        nav.append(btn(Icons.svg('chevrons-left',  { size: 14, strokeWidth: 2 }), 1, page <= 1));
        nav.append(btn(Icons.svg('chevron-left',   { size: 14, strokeWidth: 2 }), page - 1, page <= 1));

        // Page numbers (max 7)
        let start = Math.max(1, page - 3);
        let end   = Math.min(totalPages, start + 6);
        if (end - start < 6) start = Math.max(1, end - 6);

        for (let i = start; i <= end; i++) {
            const b = btn(String(i), i, false);
            if (i === page) b.addClass('is-active');
            nav.append(b);
        }

        nav.append(btn(Icons.svg('chevron-right',  { size: 14, strokeWidth: 2 }), page + 1, page >= totalPages));
        nav.append(btn(Icons.svg('chevrons-right', { size: 14, strokeWidth: 2 }), totalPages, page >= totalPages));

        this.#footer.append(nav);

        // Click delegation
        nav.on('click', (e) => {
            const b = e.target.closest('button[data-page]');
            if (!b || b.disabled) return;
            this.#ajaxPage = parseInt(b.dataset.page);
            this.#ajaxFetch();
        }, { signal: this.#eventAC.signal });
    }

    // ────────────────────────────────────────────
    // Infinite scroll
    // ────────────────────────────────────────────

    #buildSentinel() {
        this.#sentinel = razyui.spell('div.data-table-sentinel', true);
        PART.SENTINEL.apply(this.#sentinel);
        // Sentinel goes after the table inside the container
        this.#container.append(this.#sentinel);
    }

    #bindInfiniteScroll() {
        // Prefer IntersectionObserver for efficiency
        if ('IntersectionObserver' in window) {
            this.#infObserver = new IntersectionObserver((entries) => {
                for (const entry of entries) {
                    if (entry.isIntersecting) this.#infOnNearBottom();
                }
            }, {
                root: this.#resolveScrollParent(),
                rootMargin: `0px 0px ${this.#infinite.threshold}px 0px`,
            });
            this.#infObserver.observe(this.#sentinel[0]);
        } else {
            // Fallback: scroll listener
            const target = this.#resolveScrollParent() || window;
            const handler = this.#infCheckScroll.bind(this);
            razyui(target).on('scroll', handler, { passive: true, signal: this.#eventAC.signal });
            this.#infScrollCleanup = () => razyui(target).off('scroll');
        }
    }

    #resolveScrollParent() {
        // Walk up and find first scrollable parent
        let node = this.#container[0];
        while (node && node !== document.body) {
            const style = getComputedStyle(node);
            if (/(auto|scroll)/.test(style.overflow + style.overflowY)) return node;
            node = node.parentElement;
        }
        return null;
    }

    #infCheckScroll() {
        if (this.#destroyed || this.#infLoading || !this.#infHasMore) return;
        const rect = this.#sentinel.getRect();
        const viewHeight = window.innerHeight || document.documentElement.clientHeight;
        if (rect.top <= viewHeight + this.#infinite.threshold) {
            this.#infOnNearBottom();
        }
    }

    #infOnNearBottom() {
        if (this.#infLoading || !this.#infHasMore || this.#destroyed) return;
        this.#infFetchNext();
    }

    async #infFetchNext() {
        if (this.#infLoading || !this.#infHasMore || this.#destroyed) return;
        this.#infLoading = true;
        this.#infPage++;
        this.#sentinel.addClass('is-loading');

        try {
            const result = await this.#infinite.fetch({
                page: this.#infPage,
                pageSize: this.#infinite.pageSize,
            });

            if (this.#destroyed) return;

            const newRows = result?.data ?? result ?? [];
            const hasMore = result?.hasMore !== false && newRows.length >= this.#infinite.pageSize;

            if (Array.isArray(newRows) && newRows.length > 0) {
                this.#data.push(...newRows);
                this.#displayData.push(...newRows);
                this.#appendRows(newRows);
            }

            this.#infHasMore = hasMore;
            this.#infLoading = false;

            if (!hasMore) {
                this.#sentinel.removeClass('is-loading').addClass('is-done')
                    .text(this.#infinite.endMessage || this.#config.endMessage);
                this.#infObserver?.disconnect();
            } else {
                this.#sentinel.removeClass('is-loading');
                // Re-observe to handle case where sentinel is still visible
                if (this.#infObserver) {
                    this.#infObserver.unobserve(this.#sentinel[0]);
                    this.#infObserver.observe(this.#sentinel[0]);
                }
            }

            if (this.#data.length === 0) this.#showEmpty();
        } catch (err) {
            if (this.#destroyed) return;
            this.#infLoading = false;
            this.#infPage--;
            this.#sentinel.removeClass('is-loading').addClass('is-error')
                .text(this.#config.errorMessage);

            // Click to retry
            this.#sentinel.on('click', () => {
                this.#sentinel.removeClass('is-error').text('').off('click');
                this.#infFetchNext();
            }, { once: true });
        }
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    /**
     * Set data (static mode).
     * @param {Array} data
     */
    setData(data) {
        this.#data = Array.isArray(data) ? data : [];
        this.#applySortAndRender();
    }

    /**
     * Add a grouped header row above the main column header row.
     *
     * @param {Array|object} rowDef  Array of cells or { cells, className }
     * @param {object} [options]
     * @param {boolean} [options.prepend]    Insert at start
     * @param {boolean} [options.append]     Insert at end (default)
     * @param {number}  [options.index]      Insert at exact index
     * @param {number}  [options.before]     Insert before this row index
     * @param {number}  [options.beforeIndex] Insert before this row index
     * @param {number}  [options.after]      Insert after this row index
     * @param {number}  [options.afterIndex] Insert after this row index
     * @param {'prepend'|'append'|'before'|'after'} [options.position] Placement mode
     * @param {number}  [options.rowIndex]   Anchor index for position before/after
     */
    addHeaderRow(rowDef, options = {}) {
        const rows = this.#normaliseHeaderRows([rowDef]);
        if (!rows.length) return;

        const len = this.#headerRows.length;
        let insertIndex = len; // default append last row

        if (typeof options.index === 'number') {
            insertIndex = options.index;
        } else if (typeof options.beforeIndex === 'number') {
            insertIndex = options.beforeIndex;
        } else if (typeof options.before === 'number') {
            insertIndex = options.before;
        } else if (typeof options.afterIndex === 'number') {
            insertIndex = options.afterIndex + 1;
        } else if (typeof options.after === 'number') {
            insertIndex = options.after + 1;
        } else if (typeof options.rowIndex === 'number') {
            insertIndex = options.position === 'after'
                ? options.rowIndex + 1
                : options.rowIndex;
        } else if (options.position === 'prepend' || options.prepend) {
            insertIndex = 0;
        } else if (options.position === 'append' || options.append) {
            insertIndex = len;
        } else {
            insertIndex = len;
        }

        insertIndex = Math.max(0, Math.min(len, Math.floor(insertIndex)));
        this.#headerRows.splice(insertIndex, 0, rows[0]);

        this.#renderHeader();
        this.#updateSortIndicators();
    }

    /**
     * Add a body row (supports custom colspan row via `cells` / `__cells`).
     *
     * @param {object} row
     * @param {number} [index]
     */
    addRow(row, index) {
        if (typeof index === 'number' && index >= 0 && index < this.#data.length) {
            this.#data.splice(index, 0, row);
        } else {
            this.#data.push(row);
        }
        this.#applySortAndRender();
    }

    /**
     * Get current data.
     * @returns {Array}
     */
    getData() {
        return this.#data;
    }

    /**
     * Reload from AJAX source.
     */
    reload() {
        if (this.#ajax) {
            this.#ajaxFetch();
        } else if (this.#infinite) {
            this.infiniteReset();
        }
    }

    /**
     * Go to a specific AJAX page.
     * @param {number} page
     */
    goToPage(page) {
        if (!this.#ajax) return;
        this.#ajaxPage = Math.max(1, Math.min(page, Math.ceil(this.#ajaxTotal / this.#ajax.pageSize)));
        this.#ajaxFetch();
    }

    /**
     * Reset infinite scroll and reload from page 1.
     */
    infiniteReset() {
        this.#data = [];
        this.#displayData = [];
        this.#infPage = 0;
        this.#infHasMore = true;
        this.#infLoading = false;
        this.#tbody.html('');
        if (this.#sentinel) {
            this.#sentinel.removeClass('is-loading is-done is-error').text('');
        }
        if (this.#infObserver && this.#sentinel) {
            this.#infObserver.unobserve(this.#sentinel[0]);
            this.#infObserver.observe(this.#sentinel[0]);
        }
        this.#infFetchNext();
    }

    /**
     * Get page information (AJAX mode only).
     * @returns {{ page, pageSize, total, totalPages } | null}
     */
    getPageInfo() {
        if (!this.#ajax) return null;
        const ps = this.#ajax.pageSize;
        return {
            page:       this.#ajaxPage,
            pageSize:   ps,
            total:      this.#ajaxTotal,
            totalPages: Math.ceil(this.#ajaxTotal / ps),
        };
    }

    /**
     * Programmatically set a filter value and trigger re-fetch / re-render.
     * @param {string} key   — column key
     * @param {string} value — filter value (empty string to clear)
     */
    setFilter(key, value) {
        if (!this.#hasFilters || !(key in this.#filterValues)) return;
        this.#filterValues[key] = value ?? '';

        // Sync the visual input
        const ref = this.#filterInputs[key];
        if (ref) {
            if (ref instanceof HTMLInputElement) {
                ref.value = (typeof value === 'string') ? value : '';
            } else if (typeof ref.clear === 'function' && !value) {
                // DatePicker
                ref.clear();
            } else if (typeof ref.setValue === 'function') {
                ref.setValue(value ?? '');
            }
        }

        this.#onFilterChange();
    }

    /**
     * Clear all filter values and trigger re-fetch / re-render.
     */
    clearFilters() {
        if (!this.#hasFilters) return;
        for (const key of Object.keys(this.#filterValues)) {
            this.#filterValues[key] = '';

            const ref = this.#filterInputs[key];
            if (ref) {
                if (typeof ref.clear === 'function') {
                    // DatePicker
                    ref.clear();
                } else if (ref instanceof HTMLInputElement) {
                    ref.value = '';
                } else if (typeof ref.reset === 'function') {
                    ref.reset();
                } else if (typeof ref.setValue === 'function') {
                    ref.setValue('');
                }
            }
        }
        this.#onFilterChange();
    }

    /**
     * Return a compact control object for external use.
     */
    getControl() {
        const self = this;
        return {
            setData:        (d) => self.setData(d),
            addRow:         (row, index) => self.addRow(row, index),
            addHeaderRow:   (rowDef, options) => self.addHeaderRow(rowDef, options),
            getData:        ()  => self.getData(),
            reload:         ()  => self.reload(),
            goToPage:       (p) => self.goToPage(p),
            getPageInfo:    ()  => self.getPageInfo(),
            enableFilters:  (fm) => self.enableFilters(fm),
            getFilters:     ()  => ({ ...self.#filterValues }),
            setFilter:      (key, value) => self.setFilter(key, value),
            clearFilters:   ()  => self.clearFilters(),
            infiniteReset:  ()  => self.infiniteReset(),
            destroy:        ()  => self.destroy(),
            get element()       { return self.#el; },
            get destroyed()     { return self.#destroyed; },
        };
    }

    /**
     * Destroy instance and clean up.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        clearTimeout(this.#filterTimer);
        this.#eventAC?.abort();
        if (this.#infObserver) {
            this.#infObserver.disconnect();
            this.#infObserver = null;
        }
        if (this.#infScrollCleanup) {
            this.#infScrollCleanup();
            this.#infScrollCleanup = null;
        }
        if (this.#container) this.#container.detach();
    }
};

export default DataTable;
